// 三载体一致:HTML→docx Blob,零视觉挂载
import htmlToDocx from 'https://cdn.jsdelivr.net/npm/@turbodocx/html-to-docx@1/+esm';
// 默认导出即函数(非解构);第 2/4 参为页眉/页脚 HTML,不用则传 null
const blob = await htmlToDocx(
  data.html,
  data.headerHTML ?? null,
  {
    orientation: data.orientation ?? 'portrait',
    margins: data.margins,
    title: data.title,
    font: data.font,
    fontSize: data.fontSize,
    table: { row: { cantSplit: true } }
  },
  data.footerHTML ?? null
);
const url = URL.createObjectURL(blob); // <a href=url download='out.docx'>
